import{_ as t,o,c as a,a2 as r}from"./chunks/framework.Crpw6aS5.js";const p=JSON.parse('{"title":"企业收购","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-scene/企业收购.md","filePath":"05_quotes/by-scene/企业收购.md"}'),c={name:"05_quotes/by-scene/企业收购.md"};function u(l,e,q,s,h,n){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="企业收购" tabindex="-1">企业收购 <a class="header-anchor" href="#企业收购" aria-label="Permalink to &quot;企业收购&quot;">​</a></h1><blockquote><p>&quot;收购就像婚姻：婚前要充分了解对方，婚后要充分容忍对方。但现实是，很多收购在婚前就已经出了问题。&quot;——巴菲特</p></blockquote><hr><h2 id="核心金句" tabindex="-1">核心金句 <a class="header-anchor" href="#核心金句" aria-label="Permalink to &quot;核心金句&quot;">​</a></h2><blockquote><p>&quot;我们收购企业有三个标准：业务好理解、有长期竞争优势、由诚实能干的经理运营。而且价格要合理。&quot;</p></blockquote><blockquote><p>&quot;最糟糕的收购是那些在行业景气高点、基于乐观预测做出的高溢价收购。这些交易在签字时就注定了失败。&quot;</p></blockquote><blockquote><p>&quot;商誉会计不是问题，收购时为商誉支付过多的价格才是问题。&quot;</p></blockquote><blockquote><p>&quot;我们对收购的企业几乎不干涉管理。充分授权的前提是找对人。找错人的代价是巨大的。&quot;</p></blockquote><blockquote><p>&quot;如果你在谈判时感觉良好，那通常是卖方感觉更好。收购时要逆向思考：问问自己为什么这么好的资产要卖。&quot;</p></blockquote><hr><h2 id="相关主题" tabindex="-1">相关主题 <a class="header-anchor" href="#相关主题" aria-label="Permalink to &quot;相关主题&quot;">​</a></h2><p><a href="/search.html?q=管理层">管理层</a> · <a href="/search.html?q=资本配置">资本配置</a> · <a href="/search.html?q=声誉">声誉</a> · <a href="/search.html?q=护城河">护城河</a></p>',12)])])}const i=t(c,[["render",u]]);export{p as __pageData,i as default};
